ANTAL_GRUPPER = 3

class Grupp:
  def __init__ (self, namn, ständig_medlem):
    self.gruppnamn = namn
    self.medlemmar = [ständig_medlem]

  def __str__ (self):
    sträng = self.gruppnamn + " har följande medlemmar: " 
    for medlem in self.medlemmar:
        sträng += str(medlem +  ", ")
    return sträng[0:-2]

  def __lt__(self, other):
    if self.gruppnamn < other.gruppnamn:
      return True
    else:
      return False

  def lägg_till_medlem(self, ny_medlem):
    self.medlemmar.append(ny_medlem)

  def ta_bort_medlem(self, medlem):
    if medlem in self.medlemmar:
      self.medlemmar.remove(medlem)
      print(medlem, "är borttagen")
    else:
      print("Medlemen finns inte gruppen. ")

  def ordförande(self):
    if len(self.medlemmar) == 0:
      print("Finns inga medlemmar och ingen ordförande!")
      return None
    ordförande = self.medlemmar[0]
    for i in range(len(self.medlemmar)):
      if len(ordförande) < len(self.medlemmar[i]):
        ordförande = self.medlemmar[i]
    return ordförande

def huvudprogram():
  grupper = []
  namn = input("Vad heter den ständiga medlemen ?")
  for i in range(ANTAL_GRUPPER):
    gruppnamn = input("Vad heter grupp " + str(i +1) + "? ")
    grupp = Grupp(gruppnamn, namn)
    grupper.append(grupp)

  for grupp in grupper:
    namn = input("Vem vill du lägga till i grupp " + grupp.gruppnamn +"? ")
    grupp.lägg_till_medlem(namn)

  grupper.sort() #Använder __lt__ för sortering, vilken som är minst  
  for objekt in grupper:
    print(objekt)

  for grupp in grupper:
    print("Ordförande i gruppen", grupp.gruppnamn, "är", grupp.ordförande())


huvudprogram()
